#include <bits/stdc++.h>
using namespace std;
int a[200001];
int main(){
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    sort(a+1,a+n+1);
    int cnt=0,num;
    for(int i=1;i<=n;i++){
        if(i==1)num=a[i],cnt=1;
        else if(a[i]!=num){
            cout<<num<<' '<<cnt<<'\n';
            num=a[i],cnt=1;
        }else cnt++;
    }
    if(cnt)cout<<num<<' '<<cnt;
    return 0;
}
